// Bitflag const enums — ordered-unique literal sets per bitflag field (ADR-0012)
/** Bitflag set for `comparison_operator.operators`. */
export const enum Operators {
  Lt = 1 << 0,
  Le = 1 << 1,
  Eq = 1 << 2,
  Ne = 1 << 3,
  Ge = 1 << 4,
  Gt = 1 << 5,
  NeAlt = 1 << 6,
  In = 1 << 7,
  NotIn = 1 << 8,
  Is = 1 << 9,
  IsNot = 1 << 10,
}
